head.b:skin:
  :root {
    /* DARK MODE (DEFAULT) - Deep Slate & Blue/Purple Tech Palette */
    --bg-main: #0B0F19;
    --bg-secondary: #111827;
    --card-bg: rgba(17, 24, 39, 0.7);
    --card-hover: rgba(31, 41, 55, 0.8);
    --text-primary: #F3F4F6;
    --text-secondary: #9CA3AF;
    --border-color: rgba(255, 255, 255, 0.1);
    --border-hover: rgba(255, 255, 255, 0.2);
    
    --accent: #3B82F6; /* Tech Blue */
    --accent-hover: #2563EB;
    --accent-glow: rgba(59, 130, 246, 0.4);
    --accent-secondary: #8B5CF6; /* Tech Purple */
    
    --font-main: 'Inter', sans-serif;
    --font-mono: 'JetBrains Mono', monospace;
    
    --radius-sm: 8px;
    --radius-md: 12px;
    --radius-lg: 20px;
    --shadow-sm: 0 4px 6px -1px rgba(0, 0, 0, 0.1), 0 2px 4px -1px rgba(0, 0, 0, 0.06);
    --shadow-md: 0 10px 15px -3px rgba(0, 0, 0, 0.3), 0 4px 6px -2px rgba(0, 0, 0, 0.15);
    --shadow-glow: 0 0 20px var(--accent-glow);
  }
  
  /* LIGHT MODE - Clean, crisp white & gray */
  [data-theme="light"] {
    --bg-main: #F8FAFC;
    --bg-secondary: #F1F5F9;
    --card-bg: rgba(255, 255, 255, 0.8);
    --card-hover: rgba(255, 255, 255, 1);
    --text-primary: #0F172A;
    --text-secondary: #475569;
    --border-color: rgba(0, 0, 0, 0.08);
    --border-hover: rgba(0, 0, 0, 0.15);
    
    --accent: #2563EB;
    --accent-hover: #1D4ED8;
    --accent-glow: rgba(37, 99, 235, 0.2);
    --accent-secondary: #6D28D9;
    
    --shadow-sm: 0 4px 6px -1px rgba(0, 0, 0, 0.05);
    --shadow-md: 0 10px 15px -3px rgba(0, 0, 0, 0.08);
  }
  
  * { margin:0; padding:0; box-sizing:border-box; }
  ::selection { background: var(--accent); color: #fff; }
  html { scroll-behavior: smooth; }
  body {
    font-family: var(--font-main);
    font-size: 1rem;
    background: var(--bg-main);
    color: var(--text-primary);
    transition: background 0.4s ease, color 0.4s ease;
    overflow-x: hidden;
    line-height: 1.6;
  }
  
  h1, h2, h3, h4, h5, h6 {
    font-weight: 700;
    color: var(--text-primary);
    letter-spacing: -0.02em;
  }
  a { text-decoration: none; color: inherit; transition: color 0.2s; }

  /* ── AMBIENT TECH BACKGROUND (Clean & Readable) ── */
  .tech-bg { position: fixed; inset: 0; z-index: -5; background: var(--bg-main); overflow: hidden; pointer-events: none; transition: background 0.4s; }
  
  /* Subtle Panning Dot Grid */
  .tech-grid {
    position: absolute; inset: -50%;
    background-image: radial-gradient(var(--border-color) 1px, transparent 1px);
    background-size: 24px 24px;
    animation: panGrid 90s linear infinite;
    opacity: 0.6;
  }
  @keyframes panGrid {
    0% { transform: translateY(0); }
    100% { transform: translateY(50%); }
  }
  
  /* Glowing Abstract Orbs */
  .tech-orb { position: absolute; border-radius: 50%; filter: blur(100px); opacity: 0.3; animation: floatOrb 25s ease-in-out infinite alternate; transition: background 0.5s; }
  .orb-1 { width: 50vw; height: 50vw; background: var(--accent); top: -20%; left: -10%; }
  .orb-2 { width: 45vw; height: 45vw; background: var(--accent-secondary); bottom: -10%; right: -10%; animation-delay: -5s; animation-direction: alternate-reverse; }
  @keyframes floatOrb {
    0% { transform: translate(0, 0) scale(1); }
    100% { transform: translate(5vw, 5vh) scale(1.1); }
  }

  /* ── PROGRESS BAR ── */
  #reading-progress {
    position: fixed; top: 0; left: 0; height: 3px;
    background: linear-gradient(90deg, var(--accent), var(--accent-secondary));
    z-index: 99999; width: 0%; transition: width 0.1s linear;
  }

  /* ── SCROLL REVEAL ── */
  .reveal { opacity: 0; transform: translateY(20px); transition: opacity 0.6s cubic-bezier(0.16, 1, 0.3, 1), transform 0.6s cubic-bezier(0.16, 1, 0.3, 1); }
  .reveal.visible { opacity: 1; transform: translateY(0); }
  .delay-1 { transition-delay: 0.1s; }
  .delay-2 { transition-delay: 0.2s; }
  
  /* ── GLASSMORPHISM CARDS ── */
  .glass-card {
    background: var(--card-bg);
    backdrop-filter: blur(16px); -webkit-backdrop-filter: blur(16px);
    border: 1px solid var(--border-color);
    border-radius: var(--radius-md);
    padding: 2rem; transition: all 0.3s ease;
    box-shadow: var(--shadow-sm);
  }
  .glass-card:hover {
    background: var(--card-hover);
    border-color: var(--border-hover);
    box-shadow: var(--shadow-md);
    transform: translateY(-3px);
  }

  /* ── NAV ── */
  nav { position: sticky; top: 0; z-index: 100; background: rgba(11, 15, 25, 0.7); backdrop-filter: blur(12px); border-bottom: 1px solid var(--border-color); transition: background 0.3s; }
  [data-theme="light"] nav { background: rgba(248, 250, 252, 0.8); }
  .nav-container { display: flex; align-items: center; justify-content: space-between; width: 100%; max-width: 1200px; padding: 1rem 2rem; margin: 0 auto; }
  .nav-logo-section .widget { margin: 0; }
  .nav-logo { font-family: var(--font-mono); font-size: 1.4rem; font-weight: 700; color: var(--text-primary); letter-spacing: -0.5px; }
  .nav-logo span { color: var(--accent); }
  
  .nav-right { display: flex; align-items: center; gap: 2rem; }
  .nav-links-wrapper .widget { margin: 0; }
  .nav-links { display: flex; gap: 2rem; list-style: none; align-items: center; margin: 0; padding: 0; }
  .nav-links a { color: var(--text-secondary); font-size: 0.95rem; font-weight: 500; transition: color 0.2s; }
  .nav-links a:hover { color: var(--text-primary); }
  
  /* ── DROPDOWN ── */
  .dropdown { position: relative; display: inline-block; }
  .dropdown .dropbtn { cursor: pointer; display: flex; align-items: center; gap: 4px; }
  .dropdown-content { display: none; position: absolute; background-color: var(--bg-secondary); border: 1px solid var(--border-color); border-radius: var(--radius-sm); min-width: 200px; top: 100%; left: -1rem; z-index: 101; padding: 0.5rem 0; box-shadow: var(--shadow-md); overflow: hidden; }
  .dropdown-content a { color: var(--text-primary); padding: 0.75rem 1.5rem; display: block; font-size: 0.95rem; transition: background 0.2s; }
  .dropdown-content a:hover { background-color: var(--border-color); color: var(--accent); }
  .dropdown:hover .dropdown-content { display: block; }
  
  .hamburger { display: none; background: none; border: none; cursor: pointer; padding: 0.5rem; }
  .hamburger svg { width: 28px; height: 28px; fill: var(--text-primary); }

  /* ── SEARCH BAR ── */
  .search-form { display: flex; align-items: center; position: relative; }
  .search-input { background: var(--bg-secondary); border: 1px solid var(--border-color); border-radius: 20px; color: var(--text-primary); padding: 0.5rem 1rem 0.5rem 2.2rem; font-family: var(--font-main); font-size: 0.9rem; width: 180px; transition: all 0.3s ease; }
  .search-input::placeholder { color: var(--text-secondary); }
  .search-input:focus { outline: none; border-color: var(--accent); width: 220px; box-shadow: 0 0 0 3px var(--accent-glow); background: var(--bg-main); }
  .search-btn { position: absolute; left: 12px; background: none; border: none; padding: 0; display: flex; align-items: center; justify-content: center; cursor: pointer; }
  .search-btn svg { width: 16px; height: 16px; fill: var(--text-secondary); transition: fill 0.2s; }
  .search-input:focus + .search-btn svg, .search-btn:hover svg { fill: var(--accent); }

  /* ── THEME TOGGLE ── */
  #theme-toggle { background: var(--bg-secondary); border: 1px solid var(--border-color); border-radius: 20px; width: 56px; height: 30px; cursor: pointer; position: relative; transition: all 0.3s; flex-shrink: 0; display: flex; align-items: center; justify-content: space-between; padding: 0 6px; }
  #theme-toggle::after { content: ''; position: absolute; top: 3px; left: 3px; width: 22px; height: 22px; border-radius: 50%; background: var(--accent); transition: transform 0.3s cubic-bezier(0.16, 1, 0.3, 1); box-shadow: var(--shadow-sm); }
  [data-theme="light"] #theme-toggle::after { transform: translateX(26px); }
  .toggle-icon { font-size: 12px; z-index: 1; pointer-events: none; }

  /* ── BUTTONS ── */
  .btn-primary, .btn-secondary {
    display: inline-flex; align-items: center; justify-content: center; gap: 8px; padding: 0.8rem 1.8rem;
    font-weight: 500; font-size: 0.95rem; border-radius: var(--radius-sm); text-decoration: none; cursor: pointer;
    transition: all 0.2s ease;
  }
  .btn-primary { background: var(--accent); color: #fff !important; border: 1px solid transparent; box-shadow: var(--shadow-sm); }
  .btn-primary:hover { background: var(--accent-hover); transform: translateY(-2px); box-shadow: var(--shadow-glow); }
  .btn-secondary { background: transparent; color: var(--text-primary) !important; border: 1px solid var(--border-color); }
  .btn-secondary:hover { background: var(--border-color); transform: translateY(-2px); }

  /* ── HERO ── */
  .hero { min-height: 85vh; padding: 4rem 2rem; position: relative; display: flex; flex-direction: column; align-items: center; justify-content: center; z-index: 10; text-align: center; }
  .hero-tag { display: inline-flex; align-items: center; gap: 8px; background: var(--bg-secondary); border: 1px solid var(--border-color); border-radius: 20px; padding: 6px 16px; font-family: var(--font-mono); font-size: 0.8rem; color: var(--text-secondary); margin-bottom: 2rem; }
  .hero-tag .dot { width: 8px; height: 8px; border-radius: 50%; background: #10B981; box-shadow: 0 0 10px rgba(16, 185, 129, 0.5); }
  .hero-title { font-size: clamp(3rem, 6vw, 5rem); font-weight: 800; line-height: 1.1; margin-bottom: 1.5rem; letter-spacing: -0.03em; }
  .hero-title span { background: linear-gradient(135deg, var(--accent), var(--accent-secondary)); -webkit-background-clip: text; -webkit-text-fill-color: transparent; }
  .hero-desc { font-size: 1.15rem; color: var(--text-secondary); margin: 0 auto 3rem auto; max-width: 650px; line-height: 1.7; }
  .hero-actions { display: flex; gap: 1rem; flex-wrap: wrap; justify-content: center; }

  /* ── GITHUB & YOUTUBE GRID ── */
  .stats-yt-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 2rem; width: 100%; max-width: 1000px; margin-top: 5rem; z-index: 10; }
  .social-banner { @extend .glass-card; display: flex; flex-direction: column; align-items: center; text-align: center; gap: 1.5rem; padding: 3rem 2rem; border-top: 3px solid transparent; }
  .social-banner.git { border-top-color: var(--text-primary); }
  .social-banner.yt { border-top-color: #EF4444; }
  .social-banner .icon { width: 48px; height: 48px; fill: var(--text-primary); transition: transform 0.3s; }
  .social-banner.yt .icon { fill: #EF4444; }
  .social-banner:hover .icon { transform: scale(1.1) translateY(-5px); }
  .social-banner h2 { font-size: 1.5rem; font-weight: 700; }
  .social-banner p { color: var(--text-secondary); font-size: 0.95rem; line-height: 1.6; max-width: 300px; }

  /* ── SECTIONS ── */
  section.standard-section { padding: 6rem 2rem; max-width: 1100px; margin: 0 auto; width: 100%; position: relative; z-index: 10; }
  .section-label { font-family: var(--font-mono); font-size: 0.85rem; color: var(--accent); font-weight: 500; text-transform: uppercase; letter-spacing: 0.05em; margin-bottom: 0.5rem; }
  .section-title { font-size: clamp(2rem, 4vw, 3rem); font-weight: 800; margin-bottom: 3rem; }

  /* ── ABOUT ── */
  .about-grid { display: grid; grid-template-columns: 1.2fr 0.8fr; gap: 3rem; align-items: start; }
  .about-text { color: var(--text-secondary); font-size: 1.1rem; }
  .about-text p { margin-bottom: 1.5rem; }
  .about-text strong { color: var(--text-primary); font-weight: 600; }
  
  .about-highlights { display: flex; flex-direction: column; gap: 1rem; }
  .highlight-item { @extend .glass-card; padding: 1.25rem 1.5rem; display: flex; align-items: center; gap: 1rem; }
  .highlight-icon { font-size: 1.5rem; display: flex; align-items: center; justify-content: center; width: 40px; height: 40px; background: var(--bg-secondary); border-radius: var(--radius-sm); border: 1px solid var(--border-color); }
  .highlight-info strong { display: block; font-size: 1rem; color: var(--text-primary); margin-bottom: 2px; }
  .highlight-info span { font-size: 0.85rem; color: var(--text-secondary); }
  
  /* ── EXPERIENCE TIMELINE ── */
  .timeline { position: relative; padding-left: 2rem; }
  .timeline::before { content: ''; position: absolute; left: 0; top: 0; bottom: 0; width: 2px; background: var(--border-color); }
  .timeline-item { position: relative; margin-bottom: 3rem; }
  .timeline-dot { position: absolute; left: -2.35rem; top: 0.2rem; width: 14px; height: 14px; border-radius: 50%; background: var(--bg-main); border: 2px solid var(--accent); transition: background 0.3s; }
  .timeline-item:hover .timeline-dot { background: var(--accent); box-shadow: 0 0 10px var(--accent-glow); }
  .timeline-body { @extend .glass-card; padding: 2rem; margin-top: -0.5rem; }
  .timeline-period { font-family: var(--font-mono); font-size: 0.85rem; color: var(--accent); margin-bottom: 0.5rem; }
  .timeline-role { font-size: 1.25rem; font-weight: 700; color: var(--text-primary); margin-bottom: 0.25rem; }
  .timeline-org { font-size: 1rem; color: var(--text-secondary); margin-bottom: 1.25rem; font-weight: 500; }
  .timeline-points { list-style: none; display: flex; flex-direction: column; gap: 0.5rem; }
  .timeline-points li { font-size: 0.95rem; color: var(--text-secondary); position: relative; padding-left: 1.25rem; }
  .timeline-points li::before { content: '→'; position: absolute; left: 0; color: var(--accent); font-family: var(--font-mono); }

  /* ── PROJECTS ── */
  .projects-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(320px, 1fr)); gap: 2rem; }
  .project-card { @extend .glass-card; display: flex; flex-direction: column; }
  .project-date { font-family: var(--font-mono); font-size: 0.8rem; color: var(--text-secondary); margin-bottom: 1rem; }
  .project-name { font-size: 1.25rem; font-weight: 700; color: var(--text-primary); margin-bottom: 0.75rem; }
  .project-desc { font-size: 0.95rem; color: var(--text-secondary); margin-bottom: 1.5rem; flex-grow: 1; }
  .project-link { font-size: 0.9rem; font-weight: 600; color: var(--accent); display: inline-flex; align-items: center; gap: 4px; transition: gap 0.2s; }
  .project-card:hover .project-link { gap: 8px; }

  /* ── SKILLS & CERTS ── */
  .skills-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(280px, 1fr)); gap: 1.5rem; }
  .skill-category { @extend .glass-card; padding: 1.5rem; }
  .skill-cat-title { font-family: var(--font-mono); font-size: 0.85rem; color: var(--text-primary); margin-bottom: 1rem; text-transform: uppercase; letter-spacing: 0.05em; }
  .skill-tags { display: flex; flex-wrap: wrap; gap: 8px; }
  .skill-tag { padding: 4px 12px; background: var(--bg-secondary); border: 1px solid var(--border-color); border-radius: 20px; font-size: 0.85rem; color: var(--text-secondary); transition: all 0.2s; }
  .skill-tag:hover { background: var(--border-color); color: var(--text-primary); border-color: var(--text-secondary); }

  .certs-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(220px, 1fr)); gap: 1.5rem; margin-top: 2rem; }
  .cert-card { @extend .glass-card; padding: 1.5rem; display: flex; flex-direction: column; gap: 0.25rem; }
  .cert-issuer { font-family: var(--font-mono); font-size: 0.75rem; color: var(--accent); text-transform: uppercase; }
  .cert-name { font-size: 1rem; font-weight: 600; color: var(--text-primary); }

  /* ── BLOG GRID ── */
  .blog-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(320px, 1fr)); gap: 2rem; }
  .blog-card { @extend .glass-card; display: flex; flex-direction: column; padding: 2rem; }
  .blog-date { font-family: var(--font-mono); font-size: 0.8rem; color: var(--text-secondary); margin-bottom: 0.75rem; }
  .blog-title { font-size: 1.25rem; font-weight: 700; margin-bottom: 1rem; line-height: 1.4; }
  .blog-title a { color: var(--text-primary); transition: color 0.2s; }
  .blog-title a:hover { color: var(--accent); }
  .blog-snippet { font-size: 0.95rem; color: var(--text-secondary); margin-bottom: 1.5rem; flex-grow: 1; }
  .read-more { font-weight: 500; font-size: 0.9rem; color: var(--accent); display: inline-flex; align-items: center; gap: 4px; transition: gap 0.2s; }
  .blog-card:hover .read-more { gap: 8px; }
  
  /* ── FULL POST VIEW ── */
  .post-container { @extend .glass-card; max-width: 850px; margin: 2rem auto; padding: 3rem; }
  @media (max-width: 768px) { .post-container { padding: 2rem 1.5rem; } }
  
  .post-header { text-align: center; margin-bottom: 3rem; }
  .post-header h1 { font-size: clamp(2rem, 4vw, 3rem); font-weight: 800; margin: 0.5rem 0 1.5rem 0; line-height: 1.2; }
  .post-meta-tags { display: flex; flex-wrap: wrap; justify-content: center; gap: 1rem; font-family: var(--font-mono); font-size: 0.85rem; color: var(--text-secondary); }
  .post-tag { color: var(--accent); }
  
  .post-hero-image { width: 100%; aspect-ratio: 16 / 9; overflow: hidden; border-radius: var(--radius-sm); border: 1px solid var(--border-color); margin: 0 auto 3rem auto; }
  .post-hero-image img { width: 100% !important; height: 100% !important; object-fit: cover !important; transition: transform 0.5s; }
  .post-hero-image:hover img { transform: scale(1.02); }

  .post-body .separator, .post-body img { display: none !important; }
  .post-body { font-size: 1.1rem; color: var(--text-primary); }
  .post-body h2, .post-body h3 { font-weight: 700; margin: 2.5rem 0 1rem; color: var(--text-primary); }
  .post-body p { margin-bottom: 1.5rem; color: var(--text-secondary); }
  .post-body a { color: var(--accent); text-decoration: underline; text-decoration-color: var(--border-color); text-underline-offset: 4px; transition: all 0.2s; }
  .post-body a:hover { text-decoration-color: var(--accent); }
  
  .post-body blockquote { border-left: 3px solid var(--accent); background: var(--bg-secondary); padding: 1.5rem; margin: 2rem 0; border-radius: 0 var(--radius-sm) var(--radius-sm) 0; font-style: italic; color: var(--text-primary); }
  .post-body pre { background: var(--bg-secondary); border: 1px solid var(--border-color); padding: 1.5rem; overflow-x: auto; margin: 2rem 0; border-radius: var(--radius-sm); }
  .post-body code { font-family: var(--font-mono); font-size: 0.9rem; color: var(--accent-secondary); }

  /* ── CONTACT ── */
  .contact-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 3rem; }
  .contact-info { display: flex; flex-direction: column; gap: 1rem; }
  .contact-item { @extend .glass-card; padding: 1.25rem 1.5rem; display: flex; align-items: center; gap: 1.25rem; text-decoration: none; }
  .contact-icon { font-size: 1.25rem; display: flex; align-items: center; justify-content: center; width: 40px; height: 40px; background: var(--bg-secondary); border-radius: var(--radius-sm); border: 1px solid var(--border-color); color: var(--text-primary); }
  .contact-label { font-size: 0.85rem; color: var(--text-secondary); margin-bottom: 2px; }
  .contact-value { font-size: 1rem; font-weight: 600; color: var(--text-primary); }
  
  .contact-card { @extend .glass-card; display: flex; flex-direction: column; justify-content: center; gap: 1.5rem; background: linear-gradient(145deg, var(--card-bg), var(--bg-secondary)); border: 1px solid var(--accent-glow); }
  .contact-card h3 { font-size: 1.5rem; font-weight: 700; }
  .contact-card p { font-size: 1rem; color: var(--text-secondary); }

  /* ── ADS BLOCKS ── */
  .ad-sponsor-block {
    margin: 2rem auto; text-align: center; min-height: 100px; 
    background: var(--bg-secondary); border: 1px dashed var(--border-color); border-radius: var(--radius-sm);
    display: flex; flex-direction: column; align-items: center; justify-content: center;
    position: relative; padding: 1.5rem; z-index: 10;
  }
  .ad-sponsor-label {
    position: absolute; top: -10px; background: var(--bg-main); color: var(--text-secondary);
    font-family: var(--font-mono); font-size: 0.75rem; padding: 0 10px; border: 1px solid var(--border-color); border-radius: 10px;
  }

  /* ── FOOTER & SOCIAL ICONS ── */
  .site-footer { border-top: 1px solid var(--border-color); background: var(--bg-secondary); padding: 4rem 2rem 2rem; margin-top: 4rem; position: relative; z-index: 10; text-align: center; }
  .footer-bottom { max-width: 1200px; margin: 0 auto; display: flex; flex-direction: column; gap: 2.5rem; align-items: center; }
  
  .social-links { display: flex; gap: 1rem; justify-content: center; flex-wrap: wrap; }
  .social-icon { display: flex; align-items: center; justify-content: center; width: 48px; height: 48px; background: var(--bg-main); border: 1px solid var(--border-color); border-radius: 50%; color: var(--text-secondary); transition: all 0.3s ease; box-shadow: var(--shadow-sm); }
  .social-icon svg { width: 20px; height: 20px; fill: currentColor; }
  .social-icon:hover { transform: translateY(-3px); background: var(--card-bg); color: var(--text-primary); border-color: var(--border-hover); box-shadow: var(--shadow-md); }
  
  /* Brand specific hovers */
  .social-icon.insta:hover { color: #E1306C; border-color: #E1306C; }
  .social-icon.yt:hover { color: #FF0000; border-color: #FF0000; }
  .social-icon.tg:hover { color: #0088cc; border-color: #0088cc; }
  .social-icon.in:hover { color: #0A66C2; border-color: #0A66C2; }
  .social-icon.be:hover { color: #1769ff; border-color: #1769ff; }
  .social-icon.git:hover { color: var(--text-primary); border-color: var(--text-primary); }

  .footer-text { font-size: 0.95rem; color: var(--text-secondary); display: flex; flex-wrap: wrap; justify-content: center; align-items: center; gap: 2rem; width: 100%; border-top: 1px solid var(--border-color); padding-top: 2rem; }
  .inline-legal-links { display: flex; gap: 1.5rem; }
  .inline-legal-links a { font-weight: 500; transition: color 0.2s; }
  .inline-legal-links a:hover { color: var(--text-primary); }
  .footer-credit span { color: var(--accent); font-weight: 600; }

  /* ── MOBILE VIEW ── */
  @media (max-width: 768px) {
    .hero { padding: 6rem 1.5rem 3rem; }
    .hero-title { font-size: 2.5rem; }
    .stats-yt-grid, .about-grid, .contact-grid { grid-template-columns: 1fr; }
    .hamburger { display: block; }
    .nav-right {
      display: none; position: absolute; top: 100%; left: 0; width: 100%;
      background: var(--bg-main); border-bottom: 1px solid var(--border-color);
      flex-direction: column; padding: 1.5rem; gap: 1.5rem; z-index: 100; box-shadow: var(--shadow-md);
    }
    .nav-right.active { display: flex; }
    .nav-links { flex-direction: column; width: 100%; gap: 1rem; }
    .search-form { width: 100%; order: -1; margin-bottom: 0.5rem; }
    .search-input { width: 100%; }
    .dropdown-content { position: static; box-shadow: none; border: none; border-left: 2px solid var(--border-color); border-radius: 0; padding-left: 1rem; margin-top: 0.5rem; background: transparent; display: none; }
    .dropdown:hover .dropdown-content { display: block; }
    .footer-text { flex-direction: column; gap: 1rem; text-align: center; }
  }
  
  /* ── SCROLLBAR ── */
  ::-webkit-scrollbar { width: 8px; }
  ::-webkit-scrollbar-track { background: var(--bg-main); }
  ::-webkit-scrollbar-thumb { background: var(--border-hover); border-radius: 10px; }
  ::-webkit-scrollbar-thumb:hover { background: var(--text-secondary); }

body.script:
//
  /* ── THEME (DARK/LIGHT) TOGGLE ── */
  function toggleTheme() {
    const body = document.body;
    const current = body.getAttribute('data-theme');
    body.setAttribute('data-theme', current === 'light' ? '' : 'light');
    localStorage.setItem('theme', body.getAttribute('data-theme'));
  }
  
  (function() {
    const saved = localStorage.getItem('theme');
    if (saved === 'light') document.body.setAttribute('data-theme', 'light');
  })();

  /* ── MOBILE MENU ── */
  function toggleMenu() {
    const navMenu = document.getElementById('nav-menu');
    navMenu.classList.toggle('active');
  }

  /* ── SCROLL REVEAL ── */
  const observer = new IntersectionObserver((entries) => {
    entries.forEach(e => {
      if (e.isIntersecting) {
        e.target.classList.add('visible');
        observer.unobserve(e.target);
      }
    });
  }, { threshold: 0.1, rootMargin: '0px 0px -40px 0px' });

  const revealElements = document.querySelectorAll('.reveal');
  if(revealElements.length > 0) {
      revealElements.forEach(el => observer.observe(el));
  }
  
  /* ── READING PROGRESS BAR ── */
  window.addEventListener('scroll', () => {
    const winScroll = document.body.scrollTop || document.documentElement.scrollTop;
    const height = document.documentElement.scrollHeight - document.documentElement.clientHeight;
    const scrolled = (winScroll / height) * 100;
    const progressBar = document.getElementById('reading-progress');
    if (progressBar) progressBar.style.width = scrolled + '%';
  });
  
  /* ── CLEANUP LEFTOVER SPACES ── */
  document.addEventListener("DOMContentLoaded", function() {
    if (document.querySelector('.post-container')) {
      const postBodies = document.querySelectorAll('.post-body');
      postBodies.forEach(body => {
        let node = body.firstChild;
        while (node) {
          let next = node.nextSibling;
          if (node.nodeName === 'BR' || 
             (node.nodeType === 3 && node.textContent.trim() === '') ||
             (node.classList && node.classList.contains('separator')) ||
             (node.nodeName === 'P' && node.innerHTML.trim() === '')) {
            node.remove();
          } else {
            break;
          }
          node = next;
        }
      });
    }
  });
//
